</div><!-- .page-wrapper -->

<script defer>
let scrollTimeout, phasesLoaded = false;

const stealthTrigger = document.getElementById('stealthTrigger');
if (stealthTrigger) {
  stealthTrigger.addEventListener('click', function(e) {
    e.preventDefault();
    const login = document.getElementById('stealthLogin');
    if (login) {
      login.classList.toggle('active');
      if (login.classList.contains('active')) {
        clearStatus();
        const input = login.querySelector('input');
        if (input) {
          input.focus();
          input.value = '';
        }
      } else {
        clearStatus();
      }
    }
  });
}

function showStatus(msg) {
  const statusEl = document.getElementById('stealthStatus');
  if (statusEl) statusEl.textContent = msg;
}

function clearStatus() {
  const statusEl = document.getElementById('stealthStatus');
  if (statusEl) statusEl.textContent = '';
}

function initSession() {
  return fetch('/init-session.php', { method: 'POST', credentials: 'include' })
    .then(r => {
      if (!r.ok) throw new Error('HTTP ' + r.status);
      return r.json();
    })
    .then(data => {
      if (!data || !data.csrf_token) throw new Error('No CSRF token');
      return data.csrf_token;
    });
}

const stealthPanel = document.getElementById('stealthLogin');
if (stealthPanel) {
  const stealthInput = stealthPanel.querySelector('input[type="password"]');
  if (stealthInput) {
    stealthInput.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') {
        e.preventDefault();
        const input = this;
        const pw = input.value.trim();
        if (!pw) return;

        input.disabled = true;
        showStatus('Auth...');

        initSession()
          .then(csrfToken => {
            showStatus('Sending...');
            const formData = new FormData();
            formData.append('password', pw);
            formData.append('csrf_token', csrfToken);
            return fetch('/auth.php', { method: 'POST', body: formData, credentials: 'include' })
              .then(r => r.json());
          })
          .then(data => {
            if (data && data.success) {
              showStatus('OK');
              window.location.href = '/crm.php';
            } else {
              input.style.borderBottomColor = '#ff0000';
              input.value = '';
              input.disabled = false;
              showStatus(data && data.error ? data.error : 'Failed');
              setTimeout(() => {
                input.style.borderBottomColor = '#000';
                input.focus();
                clearStatus();
              }, 300);
            }
          })
          .catch(err => {
            input.style.borderBottomColor = '#ff0000';
            input.value = '';
            input.disabled = false;
            showStatus('Error: ' + (err.message || 'unknown'));
            setTimeout(() => {
              input.style.borderBottomColor = '#000';
              input.focus();
            }, 5000);
          });
      }
    });
  }
}

document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    const panel = document.getElementById('stealthLogin');
    if (panel) panel.classList.remove('active');
  }
});



// Lazy-load Phasen-Content
const phasesContainer = document.getElementById('phases-container');
if (phasesContainer && 'IntersectionObserver' in window) {
  const observer = new IntersectionObserver((entries) => {
    if (entries[0].isIntersecting && !phasesLoaded) {
      phasesLoaded = true;
      fetch('/phases.html')
        .then(r => r.text())
        .then(html => { phasesContainer.innerHTML = html; })
        .catch(() => { phasesContainer.innerHTML = '<p>Phasen konnten nicht geladen werden.</p>'; });
    }
  }, { rootMargin: '200px' });
  observer.observe(phasesContainer);
} else {
  fetch('/phases.html').then(r => r.text()).then(html => { phasesContainer.innerHTML = html; });
}

const sections = ['preis', 'warum', 'phasen', 'diagnose', 'manifesto'];
const navLinks = document.querySelectorAll('nav a');

window.addEventListener('scroll', () => {
  if (scrollTimeout) return;
  scrollTimeout = setTimeout(() => {
    let current = '';
    sections.forEach(id => {
      const section = document.getElementById(id);
      if (section && window.scrollY >= section.offsetTop - 100) {
        current = id;
      }
    });
    navLinks.forEach(link => {
      link.classList.remove('active');
      if (link.getAttribute('href') === '#' + current) {
        link.classList.add('active');
      }
    });
    scrollTimeout = null;
  }, 150);
}, { passive: true });

async function sendDiagnose(e) {
  e.preventDefault();
  const form = document.getElementById('diagnoseForm');
  const data = new FormData(form);

  // URL normalisieren: Falls kein Protokoll, https:// hinzufügen
  let url = data.get('url') || '';
  if (url && !url.match(/^https?:\/\//i)) {
    url = 'https://' + url;
  }
  data.set('url', url);

  try {
    const res = await fetch('/api.php', { method: 'POST', body: data });
    const json = await res.json();
    if (json.success) {
      form.innerHTML = '<p style="font-family:var(--font-mono);font-size:14px;padding:24px 0;">✓ Anfrage eingegangen. Wir melden uns.</p>';
    } else {
      alert('Fehler: ' + (json.error || 'Unbekannter Fehler'));
    }
  } catch (err) {
    alert('Fehler beim Senden: ' + err.message);
  }
}
</script>

</body>
</html>
